// ═══════════════════════════════════════════════════════════════
// SPIKE HUNTER PRO v10 — CONFIG A (BEST BACKTESTED)
// Backtest: WR 57.6% | PF 2.02 | +14.24R over 42 days (33 trades)
// Strategy: Mean Reversion Buy-the-Dip (LONG only)
// Config A: Green candle + RSI rising + MinScore 40 + SL 2.0x ATR
// ═══════════════════════════════════════════════════════════════

const webhookData = $('Webhook Trigger').first().json.body;
const symbol = webhookData.symbol;
const wsPrice = parseFloat(webhookData.lastPrice);
const wsPctChange = parseFloat(webhookData.priceChangePercent);
const wsDirection = webhookData.direction;

function parseKlines(nodeName) {
  let raw = $(nodeName).first().json;
  let data = Array.isArray(raw) ? raw : (typeof raw.data === 'string' ? JSON.parse(raw.data) : raw.data);
  if (!Array.isArray(data) || data.length < 30) return null;
  return {
    open: data.map(k => parseFloat(k[1])),
    high: data.map(k => parseFloat(k[2])),
    low: data.map(k => parseFloat(k[3])),
    close: data.map(k => parseFloat(k[4])),
    volume: data.map(k => parseFloat(k[5])),
  };
}

const tf1h = parseKlines('Get Klines 1h');
if (!tf1h) return [{ json: { isHot: false, symbol, rejectReason: 'Data klines tidak cukup' } }];

const c = tf1h.close, h = tf1h.high, l = tf1h.low, o = tf1h.open, v = tf1h.volume;
const price = c[c.length - 1];
const idx = c.length - 1;

function calcEMA(p, n) {
  const k = 2/(n+1); let e = p.slice(0,n).reduce((a,b)=>a+b)/n;
  const r = new Array(n-1).fill(null); r.push(e);
  for (let i=n; i<p.length; i++) { e=(p[i]-e)*k+e; r.push(e); }
  return r;
}
function calcRSI(p, n=14) {
  if (p.length < n+1) return 50;
  let g=0,lo=0;
  for (let i=1; i<=n; i++) { let d=p[i]-p[i-1]; d>=0?g+=d:lo-=d; }
  let ag=g/n, al=lo/n;
  for (let i=n+1; i<p.length; i++) {
    let d=p[i]-p[i-1]; ag=((ag*(n-1))+(d>=0?d:0))/n; al=((al*(n-1))+(d<0?-d:0))/n;
  }
  return al===0 ? 100 : 100-(100/(1+(ag/al)));
}
function calcMACD(p) {
  const f=calcEMA(p,12), s=calcEMA(p,26), ml=[];
  for (let i=0; i<p.length; i++) if(f[i]!==null&&s[i]!==null) ml.push(f[i]-s[i]);
  if (ml.length<9) return {h:0,ph:0,cu:false,cd:false,hist:0};
  const sl=calcEMA(ml,9);
  const lm=ml[ml.length-1],ls=sl[sl.length-1]||0,pm=ml[ml.length-2]||lm,ps=sl[sl.length-2]||ls;
  return {h:lm-ls, ph:pm-ps, cu:pm<=ps&&lm>ls, cd:pm>=ps&&lm<ls, hist:lm-ls};
}
function calcATR(h,l,c,n=14) {
  if(h.length<n+1) return 0;
  let t=[h[0]-l[0]];
  for(let i=1;i<h.length;i++) t.push(Math.max(h[i]-l[i],Math.abs(h[i]-c[i-1]),Math.abs(l[i]-c[i-1])));
  let a=t.slice(0,n).reduce((x,y)=>x+y)/n;
  for(let i=n;i<t.length;i++) a=(a*(n-1)+t[i])/n;
  return a;
}
function calcADX(h,l,c,n=14) {
  if(h.length<n*3) return 0;
  let t=[],pd=[],md=[];
  for(let i=1;i<h.length;i++) {
    t.push(Math.max(h[i]-l[i],Math.abs(h[i]-c[i-1]),Math.abs(l[i]-c[i-1])));
    let u=h[i]-h[i-1],d=l[i-1]-l[i];
    pd.push(u>d&&u>0?u:0); md.push(d>u&&d>0?d:0);
  }
  let aT=t.slice(0,n).reduce((a,b)=>a+b),aP=pd.slice(0,n).reduce((a,b)=>a+b),aM=md.slice(0,n).reduce((a,b)=>a+b);
  const dx=[];
  for(let i=n;i<t.length;i++) {
    aT=aT-aT/n+t[i]; aP=aP-aP/n+pd[i]; aM=aM-aM/n+md[i];
    let pI=(aP/aT)*100,mI=(aM/aT)*100;
    dx.push((pI+mI)===0?0:Math.abs(pI-mI)/(pI+mI)*100);
  }
  if(dx.length<n) return 0;
  let a=dx.slice(0,n).reduce((x,y)=>x+y)/n;
  for(let i=n;i<dx.length;i++) a=((a*(n-1))+dx[i])/n;
  return a;
}

const _rsi = calcRSI(c);
const _prevRsi = calcRSI(c.slice(0, -1));
const _macd = calcMACD(c);
const _atr = calcATR(h, l, c);
const _adx = calcADX(h, l, c);
const e21 = calcEMA(c, 21), e50 = calcEMA(c, 50);
const E21 = e21[e21.length-1]||price, E50 = e50[e50.length-1]||price;
const avgVol = v.slice(-20).reduce((a,b)=>a+b)/20;
const volRatio = v[v.length-1]/avgVol;
let trend = 'SIDEWAYS';
if(price>E21&&E21>E50) trend = 'UPTREND';
else if(price<E21&&E21<E50) trend = 'DOWNTREND';
const recentH = Math.max(...h.slice(-50));
const recentL = Math.min(...l.slice(-50));

let score = 0;
let signal = 'NEUTRAL';
let strategy = 'WAIT';
let confidence = 'LOW';
const reasons = [];

if (wsPctChange < -3) {
  if (_rsi >= 40) { reasons.push('RSI ' + _rsi.toFixed(0) + ' tidak oversold'); }
  else {
    let ff = 0;
    for (let k = idx-5; k <= idx; k++) {
      if (k > 24) { const ll = Math.min(...l.slice(k-24, k)); if (l[k] < ll) ff++; }
    }
    if (ff >= 3) { reasons.push('FREEFALL - skip'); }
    else {
      if (E21 <= price * 1.003) { reasons.push('EMA21 tidak di atas harga'); }
      else {
        if (c[idx] <= o[idx]) { reasons.push('Candle merah - tunggu hijau'); }
        else {
          if (_rsi <= _prevRsi) { reasons.push('RSI masih turun - tunggu naik'); }
          else {
            if (_rsi < 22) { score += 20; reasons.push('RSI ' + _rsi.toFixed(0) + ' extreme'); }
            else if (_rsi < 28) { score += 15; reasons.push('RSI ' + _rsi.toFixed(0) + ' oversold'); }
            else if (_rsi < 33) { score += 10; reasons.push('RSI ' + _rsi.toFixed(0)); }
            else { score += 5; }

            const absPct = Math.abs(wsPctChange);
            if (absPct >= 8) { score += 12; reasons.push(absPct.toFixed(0) + '% crash'); }
            else if (absPct >= 5) { score += 9; reasons.push(absPct.toFixed(0) + '% drop'); }
            else if (absPct >= 4) { score += 6; }
            else { score += 3; }

            const body = Math.abs(c[idx] - o[idx]), range = h[idx] - l[idx];
            if (range > 0 && body/range > 0.4) { score += 15; reasons.push('Bullish candle'); }
            else { score += 8; reasons.push('Green candle'); }

            if (_macd.cu) { score += 10; reasons.push('MACD Cross Up'); }
            else if (_macd.h < 0 && _macd.h > _macd.ph) { score += 6; reasons.push('MACD turning'); }

            if (volRatio > 3.0) { score += 8; reasons.push('Vol ' + volRatio.toFixed(1) + 'x cap'); }
            else if (volRatio > 2.0) { score += 5; reasons.push('Vol ' + volRatio.toFixed(1) + 'x'); }
            else if (volRatio > 1.5) { score += 2; }

            const sup3d = Math.min(...l.slice(Math.max(0, idx-72), idx));
            const dSup = (price - sup3d) / price * 100;
            if (dSup < 0.5) { score += 10; reasons.push('Double bottom'); }
            else if (dSup < 1.5) { score += 6; reasons.push('Near support'); }
            else if (dSup < 3) { score += 3; }

            if (range > 0) {
              const lw = Math.min(c[idx], o[idx]) - l[idx];
              if (lw/range > 0.5) { score += 5; reasons.push('Wick up'); }
            }

            if (_adx < 20) { score += 5; reasons.push('ADX weak'); }
            else if (_adx > 35) { score -= 3; }

            if (score >= 55) { signal = 'STRONG BUY'; strategy = 'LONG'; confidence = 'VERY HIGH'; }
            else if (score >= 45) { signal = 'BUY'; strategy = 'LONG'; confidence = 'HIGH'; }
            else if (score >= 40) { signal = 'POSSIBLE LONG'; strategy = 'LONG'; confidence = 'MEDIUM'; }
          }
        }
      }
    }
  }
} else {
  reasons.push('Change ' + wsPctChange.toFixed(1) + '% - hanya proses drop > -3%');
}

let sl = 0, tp1 = 0, tp2 = 0, tp3 = 0;
let riskPct = '0';
if (strategy === 'LONG' && _atr > 0) {
  sl = price - (_atr * 2.0);
  const slDist = price - sl;
  const meanDist = Math.max(E21 - price, 0);
  tp1 = price + Math.max(meanDist * 0.4, slDist * 1.5);
  tp2 = price + Math.max(meanDist * 0.7, slDist * 2.0);
  tp3 = price + Math.max(meanDist * 1.0, slDist * 3.0);
  riskPct = ((slDist / price) * 100).toFixed(2);
}

return [{
  json: {
    symbol, price: price.toFixed(4),
    wsChange: wsPctChange.toFixed(2) + '%', wsDirection,
    signal, strategy, confidence, score,
    reasons: reasons.join(' | '),
    trend1h: trend, rsi1h: _rsi.toFixed(1),
    macdHist: _macd.hist.toFixed(6),
    macdCross: _macd.cu ? 'BULL CROSS' : (_macd.cd ? 'BEAR CROSS' : 'None'),
    adx1h: _adx.toFixed(1), volRatio: volRatio.toFixed(1) + 'x',
    ema21: E21.toFixed(4),
    support: recentL.toFixed(4), resistance: recentH.toFixed(4),
    distSupport: ((price - recentL) / price * 100).toFixed(2) + '%',
    distResistance: ((recentH - price) / price * 100).toFixed(2) + '%',
    sl: sl.toFixed(4), tp1: tp1.toFixed(4), tp2: tp2.toFixed(4), tp3: tp3.toFixed(4),
    riskPct: riskPct + '%', atr: _atr.toFixed(6),
    isHot: signal !== 'NEUTRAL',
    rejectReason: signal === 'NEUTRAL' ? 'Score ' + score + '. ' + reasons.join(', ') : '',
  }
}];
